utstanding: 'Lagu leeyahay', paidInFull: 'Wada bixiyay', downloadPdf: 'PDF', printReport: 'Print', settleBalance: 'Ka jar Lacagta', payNow: 'Bixi', paymentSuccess: 'Waa la keydiyay', refund: 'Celi', refundConfirm: 'Ma hubtaa?', refundSuccess: 'Waa la celiyay', status: 'Xaaladda', completed: 'Dhamaystiran', refunded: 'La Celiyay', selectDate: 'Dooro Taariikh'
