// Default Admin for fallback login
const DEFAULT_ADMIN: User = {
  id: '1',
  name: 'Admin User',
  email: 'admin@dhool.com',
  role: 'Admin',
  avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Admin',
