export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('user');
    return saved ? JSON.parse(saved) : null;
  });

  const [language, setLanguage] = useState<Language>(() => {
    return (localStorage.getItem('language') as Language) || 'so';
  });
  const [activeTab, setActiveTab] = useState<Tab>(Tab.DASHBOARD);
  const [isLoading, setIsLoading] = useState(true);

  // Application State
  const [products, setProducts] = useState<Product[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [appUsers, setAppUsers] = useState<User[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [patientHistory, setPatientHistory] = useState<PatientHistory[]>([]);
  const [prescriptions, setPrescriptions] = useState<Prescription[]>([]);
  const [salesReports, setSalesReports] = useState<SalesReport[]>([]);
  const [activityLogs, setActivityLogs] = useState<ActivityLog[]>([]);

  useEffect(() => {
    localStorage.setItem('language', language);
  }, [language]);

  const logActivity = async (action: string, details: string) => {
    if (!user) return;
    const newLog: ActivityLog = {
      id: Date.now().toString(),
      userId: user.id,
      userName: user.name,
      action,
      details,
      timestamp: new Date().toISOString()
    };

    try {
      await supabase.from('activity_log').insert([{
          id: newLog.id,
          user_id: newLog.userId,
          user_name: newLog.userName,
          action: newLog.action,
          details: newLog.details,
          timestamp: newLog.timestamp
      }]);
    } catch (e) {
      console.warn("DHOOL: Activity log failed to save online.");
    }

    if (user.role === 'Admin') {
       setActivityLogs(prev => [newLog, ...prev]);
    }
  };

  const fetchData = async () => {
    if (!user) {
      setIsLoading(false);
      return;
    }

    try {
      const requests = [
        supabase.from('products').select('*').order('name'),
        supabase.from('patients').select('*').order('created_at', { ascending: false }),
        supabase.from('appointments').select('*').order('date', { ascending: false }),
        supabase.from('transactions').select('*').order('created_at', { ascending: false }),
        supabase.from('employees').select('*'),
        supabase.from('expenses').select('*').order('date', { ascending: false }),
        supabase.from('patient_history').select('*').order('date', { ascending: false }),
        supabase.from('prescriptions').select('*').order('date', { ascending: false }),
        supabase.from('users').select('*'),
        supabase.from('sales_reports').select('*').order('date', { ascending: false })
      ];

      if (user.role === 'Admin') {
         requests.push(supabase.from('activity_log').select('*').order('timestamp', { ascending: false }).limit(200));
      }

      const fetchResults = await Promise.allSettled(requests);

      const getData = (idx: number) => {
          const res = fetchResults[idx];
          return res.status === 'fulfilled' && res.value.data ? res.value.data : [];
      };

      setProducts(getData(0).map((p: any) => ({ ...p, price: Number(p.price), stock: Number(p.stock) })));
      setPatients(getData(1).map((p: any) => ({ ...p, bloodType: p.blood_type, lastVisit: p.last_visit, debt: Number(p.debt) })));
      setAppointments(getData(2).map((a: any) => ({ ...a, patientName: a.patient_name, doctorName: a.doctor_name })));
      setTransactions(getData(3).map((t: any) => ({
        ...t,
        total: Number(t.total),
        paidAmount: Number(t.paid_amount),
        balance: Number(t.balance),
        cashierName: t.cashier_name,
        userId: t.user_id,
        patientId: t.patient_id,
        patientName: t.patient_name,
        itemDetails: t.item_details
      })));
      setEmployees(getData(4) as Employee[]);
      setExpenses(getData(5).map((e: any) => ({ ...e, amount: Number(e.amount) })));
      setPatientHistory(getData(6).map((h: any) => ({ ...h, patientId: h.patient_id, doctorName: h.doctor_name })));
      setPrescriptions(getData(7).map((p: any) => ({ ...p, patientId: p.patient_id, doctorName: p.doctor_name })));
      setAppUsers(getData(8) as User[]);
      setSalesReports(getData(9).map((s: any) => ({ ...s, total_sales: Number(s.total_sales), average_value: Number(s.average_value) })));

      if (user.role === 'Admin' && fetchResults.length > 10) {
         setActivityLogs(getData(10).map((l: any) => ({
            id: l.id,
            userId: l.user_id,
            userName: l.user_name,
            action: l.action,
            details: l.details,
            timestamp: l.timestamp
         })));
      }
    } catch (error) { 
      console.warn("DHOOL: Sync Error (Database might be offline):", error); 
    } finally { 
      setIsLoading(false); 
    }
  };

  useEffect(() => { 
    if (user) fetchData(); 
    else setIsLoading(false); 
  }, [user]);

  const login = async (email: string, pass: string) => {
    setIsLoading(true);

    // First, check for local fallback (emergency admin)
    if (email.toLowerCase() === DEFAULT_ADMIN.email && pass === DEFAULT_ADMIN.password) {
        setUser(DEFAULT_ADMIN);
        localStorage.setItem('user', JSON.stringify(DEFAULT_ADMIN));
        setIsLoading(false);
        return { success: true };
    }

    try {
      const { data, error } = await supabase
        .from('users')
        .select('*')
        .eq('email', email)
        .eq('password', pass)
        .maybeSingle();

      if (error) {
        console.error("Supabase Login Error:", error);
        throw new Error(error.message);
      }

      if (!data) { 
        setIsLoading(false); 
        return { success: false, error: "Email-ka ama Password-ka waa khalad." }; 
      }

      setUser(data); 
      localStorage.setItem('user', JSON.stringify(data));
      setIsLoading(false);
      return { success: true };
    } catch (e: any) {
      console.warn("DHOOL: Database connection failed, but local fallback is available.");
      setIsLoading(false);
      return { 
        success: false, 
        error: "Xiriirka database-ka waa go'an yahay. Hubi internet-ka ama xiriirka Supabase." 
      };
    }
  };

  const logout = () => { 
    if (user) logActivity('Logout', 'User logged out');
    setUser(null); 
    localStorage.removeItem('user'); 
    setActiveTab(Tab.DASHBOARD);
  };

  const updateCurrentUser = async (name: string, password?: string) => {
    if (!user) return { success: false };
    const updates: any = { name }; 
    if (password) updates.password = password;

    try {
      const { error } = await supabase.from('users').update(updates).eq('id', user.id);
      if (error) throw error;
      const updated = { ...user, ...updates }; 
      setUser(updated); 
      localStorage.setItem('user', JSON.stringify(updated));
      logActivity('Update Profile', 'User updated their profile');
      return { success: true };
    } catch (e: any) {
      return { success: false, error: e.message };
    }
  };

  const safeInsert = async (table: string, data: any, updateState: () => void) => {
    try {
      const { error } = await supabase.from(table).insert([data]);
      if (error) throw error;
      updateState();
    } catch (e: any) {
      console.error(`DHOOL Error in ${table}:`, e);
      alert(`Khalad: Xogta lama keydin karo (Database Error).`);
    }
  };

  const addPatient = async (p: Patient) => { 
    const dbObject = {
      id: p.id, name: p.name, age: p.age, phone: p.phone,
      blood_type: p.bloodType || null, last_visit: p.lastVisit,
      condition: p.condition, address: p.address || null,
      gender: p.gender || null, allergies: p.allergies || null, debt: 0
    };
    await safeInsert('patients', dbObject, () => {
      setPatients(prev => [p, ...prev]);
      logActivity('Add Patient', `Added patient: ${p.name}`);
    });
  };

  const processSale = async (items: {id: string, quantity: number}[], total: number, method: 'Cash' | 'EVC', paid: number, patientId?: string, patientName?: string) => {
    const txId = Date.now().toString();
    const txDate = new Date().toISOString();

    const tx: Transaction = { 
      id: txId, date: txDate, total, paidAmount: paid, balance: total - paid, 
      items: items.length, method, cashierName: user?.name, userId: user?.id, 
      patientId, patientName, status: 'Completed', itemDetails: items 
    };

    try {
      const { error } = await supabase.from('transactions').insert([{
         id: tx.id, date: tx.date, total: tx.total, paid_amount: tx.paidAmount,
         balance: tx.balance, items: tx.items, method: tx.method,
         cashier_name: tx.cashierName, user_id: tx.userId,
         patient_id: tx.patientId || null, patient_name: tx.patientName || null,
         status: tx.status, item_details: tx.itemDetails
      }]);

      if (error) throw error;

      for (const item of items) {
        const prod = products.find(p => p.id === item.id);
        if (prod) {
           const newStock = Math.max(0, prod.stock - item.quantity);
           await supabase.from('products').update({ stock: newStock }).eq('id', prod.id);
        }
      }

      setTransactions(prev => [tx, ...prev]);
      const { data: updatedProds } = await supabase.from('products').select('*').order('name');
      if (updatedProds) setProducts(updatedProds.map((p: any) => ({ ...p, price: Number(p.price), stock: Number(p.stock) })));

      logActivity('Sale', `Processed sale ID: ${txId} for $${total}`);
      return true;
    } catch (err) {
      console.error(err);
      alert("Iibka lama keydin karo database-ka.");
      return false;
    }
  };

  const addProduct = async (p: Product) => { await safeInsert('products', p, () => setProducts(prev => [...prev, p])); };
  const updateProduct = async (p: Product) => { 
    const { error } = await supabase.from('products').update(p).eq('id', p.id);
    if (!error) {
      setProducts(prev => prev.map(item => item.id === p.id ? p : item));
    }
  };
  const deleteProduct = async (id: string) => { 
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (!error) setProducts(prev => prev.filter(p => p.id !== id));
  };

  const updatePatient = async (p: Patient) => { 
    const dbP = { name: p.name, age: p.age, phone: p.phone, blood_type: p.bloodType, last_visit: p.lastVisit, condition: p.condition, address: p.address, gender: p.gender, allergies: p.allergies };
    const { error } = await supabase.from('patients').update(dbP).eq('id', p.id);
    if (!error) setPatients(prev => prev.map(item => item.id === p.id ? p : item));
  };

  const deletePatient = async (id: string) => { 
    const { error } = await supabase.from('patients').delete().eq('id', id);
    if (!error) setPatients(prev => prev.filter(p => p.id !== id));
  };

  const addAppointment = async (a: Appointment) => { 
    const dbA = { id: a.id, patient_name: a.patientName, doctor_name: a.doctorName, date: a.date, time: a.time, status: a.status, type: a.type };
    await safeInsert('appointments', dbA, () => setAppointments(prev => [...prev, a])); 
  };

  const updateAppointment = async (a: Appointment) => { 
    const dbA = { patient_name: a.patientName, doctor_name: a.doctorName, date: a.date, time: a.time, status: a.status, type: a.type };
    const { error } = await supabase.from('appointments').update(dbA).eq('id', a.id);
    if (!error) setAppointments(prev => prev.map(item => item.id === a.id ? a : item));
  };

  const deleteAppointment = async (id: string) => { 
    const { error } = await supabase.from('appointments').delete().eq('id', id);
    if (!error) setAppointments(prev => prev.filter(a => a.id !== id)); 
  };

  const updateAppointmentStatus = async (id: string, status: any) => { 
    const { error } = await supabase.from('appointments').update({ status }).eq('id', id);
    if (!error) setAppointments(prev => prev.map(a => a.id === id ? { ...a, status } : a)); 
  };

  const addExpense = async (e: Expense) => { await safeInsert('expenses', e, () => setExpenses(prev => [...prev, e])); };
  const updateExpense = async (e: Expense) => { 
    const { error } = await supabase.from('expenses').update(e).eq('id', e.id);
    if (!error) setExpenses(prev => prev.map(item => item.id === e.id ? e : item)); 
  };

  const deleteExpense = async (id: string) => { 
    const { error } = await supabase.from('expenses').delete().eq('id', id);
    if (!error) setExpenses(prev => prev.filter(e => e.id !== id)); 
  };

  const refundTransaction = async (id: string) => {
    const { error } = await supabase.from('transactions').update({ status: 'Refunded' }).eq('id', id);
    if (!error) setTransactions(prev => prev.map(t => t.id === id ? { ...t, status: 'Refunded' } : t));
  };

  const settleBalance = async (pId: string, pName: string, amount: number, method: any) => {
    const txId = Date.now().toString();
    try {
      const { error } = await supabase.from('transactions').insert([{
         id: txId, date: new Date().toISOString(), total: 0, paid_amount: amount,
         balance: -amount, items: 0, method, cashier_name: user?.name,
         user_id: user?.id, patient_id: pId, patient_name: pName, status: 'Completed'
      }]);
      if (error) throw error;
      fetchData(); 
    } catch (e) {
      alert("Payment failed.");
    }
  };

  const addPatientHistory = async (h: PatientHistory) => { 
     const dbH = { id: h.id, patient_id: h.patientId, date: h.date, diagnosis: h.diagnosis, treatment: h.treatment, notes: h.notes, doctor_name: h.doctorName };
     await safeInsert('patient_history', dbH, () => setPatientHistory(prev => [h, ...prev])); 
  };

  const addPrescription = async (p: Prescription) => { 
     const dbP = { id: p.id, patient_id: p.patientId, doctor_name: p.doctorName, date: p.date, medicines: p.medicines };
     await safeInsert('prescriptions', dbP, () => setPrescriptions(prev => [p, ...prev])); 
  };

  const addEmployee = async (e: Employee) => { await safeInsert('employees', e, () => setEmployees(prev => [...prev, e])); };

  const deleteEmployee = async (id: string) => { 
    const { error } = await supabase.from('employees').delete().eq('id', id);
    if (!error) setEmployees(prev => prev.filter(e => e.id !== id)); 
  };

  const addUser = async (u: User) => { 
    try {
      const { error } = await supabase.from('users').insert([u]);
      if (error) throw error;
      setAppUsers(prev => [...prev, u]); 
      return { success: true }; 
    } catch (e: any) {
      return { success: false, error: e.message };
    }
  };

  const deleteUser = async (id: string) => { 
    if (id === user?.id) return;
    const { error } = await supabase.from('users').delete().eq('id', id);
    if (!error) setAppUsers(prev => prev.filter(u => u.id !== id)); 
  };

  const t = (key: string) => (translations[language] as any)[key] || key;

  return (
    <AppContext.Provider value={{
      user, login, logout, updateCurrentUser, isLoading, language, setLanguage, activeTab, setActiveTab,
      products, addProduct, updateProduct, deleteProduct,
      patients, addPatient, updatePatient, deletePatient,
      appointments, addAppointment, updateAppointment, deleteAppointment, updateAppointmentStatus,
      transactions, salesReports, processSale, refundTransaction, settleBalance,
      employees, addEmployee, deleteEmployee,
      expenses, addExpense, updateExpense, deleteExpense,
      patientHistory, addPatientHistory,
      prescriptions, addPrescription,
      appUsers, addUser, deleteUser, t, activityLogs, logActivity
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

