  const deleteUser = async (id: string) => { await supabase.from('users').delete().eq('id', id); fetchData(); };

  const addPatientHistory = async (h: PatientHistory) => { await supabase.from('patient_history').insert([{ ...h, patient_id: h.patientId, doctor_name: h.doctorName }]); };
  const addPrescription = async (p: Prescription) => { await supabase.from('prescriptions').insert([{ ...p, patient_id: p.patientId, doctor_name: p.doctorName }]); };

