export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('user');
    return saved ? JSON.parse(saved) : null;
  });

  const [language, setLanguage] = useState<Language>(() => {
    return (localStorage.getItem('language') as Language) || 'so';
  });
  const [activeTab, setActiveTab] = useState<Tab>(Tab.DASHBOARD);
  const [isLoading, setIsLoading] = useState(false);

  // Application State
  const [products, setProducts] = useState<Product[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [appUsers, setAppUsers] = useState<User[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [patientHistory, setPatientHistory] = useState<PatientHistory[]>([]);
  const [prescriptions, setPrescriptions] = useState<Prescription[]>([]);
  const [salesReports, setSalesReports] = useState<SalesReport[]>([]);
  const [activityLogs, setActivityLogs] = useState<ActivityLog[]>([]);

  useEffect(() => {
    localStorage.setItem('language', language);
  }, [language]);

  const logActivity = async (action: string, details: string) => {
    if (!user) return;
    try {
      await supabase.from('activity_log').insert([{
          id: Date.now().toString(),
          user_id: user.id,
          user_name: user.name,
          action,
          details,
          timestamp: new Date().toISOString()
      }]);
    } catch (e) {
      console.warn("DHOOL: Activity log failed.");
    }
  };

  const fetchData = async () => {
    if (!user) return;
    setIsLoading(true);
    try {
      // Use Promise.allSettled to prevent one missing table from crashing the app
      const results = await Promise.allSettled([
        supabase.from('products').select('*').order('name'),
        supabase.from('patients').select('*').order('created_at', { ascending: false }),
        supabase.from('appointments').select('*').order('date', { ascending: false }),
        supabase.from('transactions').select('*').order('created_at', { ascending: false }),
        supabase.from('employees').select('*'),
        supabase.from('expenses').select('*'),
        supabase.from('users').select('*'),
        supabase.from('sales_reports').select('*')
      ]);

      if (results[0].status === 'fulfilled' && results[0].value.data) setProducts(results[0].value.data.map((p: any) => ({ ...p, price: Number(p.price), stock: Number(p.stock) })));
      if (results[1].status === 'fulfilled' && results[1].value.data) setPatients(results[1].value.data.map((p: any) => ({ ...p, bloodType: p.blood_type, lastVisit: p.last_visit, debt: Number(p.debt) })));
      if (results[2].status === 'fulfilled' && results[2].value.data) setAppointments(results[2].value.data.map((a: any) => ({ ...a, patientName: a.patient_name, doctorName: a.doctor_name })));
      if (results[3].status === 'fulfilled' && results[3].value.data) setTransactions(results[3].value.data.map((t: any) => ({ ...t, total: Number(t.total), paidAmount: Number(t.paid_amount), balance: Number(t.balance), cashierName: t.cashier_name, patientName: t.patient_name })));
      if (results[4].status === 'fulfilled' && results[4].value.data) setEmployees(results[4].value.data);
      if (results[5].status === 'fulfilled' && results[5].value.data) setExpenses(results[5].value.data.map((e: any) => ({ ...e, amount: Number(e.amount) })));
      if (results[6].status === 'fulfilled' && results[6].value.data) setAppUsers(results[6].value.data);
      if (results[7].status === 'fulfilled' && results[7].value.data) setSalesReports(results[7].value.data);

    } catch (error) {
      console.error("DHOOL: Global fetch error", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { 
    if (user) fetchData(); 
  }, [user]);

  const login = async (email: string, pass: string) => {
    setIsLoading(true);
    const cleanEmail = email.trim().toLowerCase();

    // EMERGENCY FALLBACK: Hardcoded admin always works even if DB is empty
    if (cleanEmail === DEFAULT_ADMIN.email && pass === DEFAULT_ADMIN.password) {
        setUser(DEFAULT_ADMIN);
        localStorage.setItem('user', JSON.stringify(DEFAULT_ADMIN));
        setIsLoading(false);
        return { success: true };
    }

    try {
      const { data, error } = await supabase
        .from('users')
        .select('*')
        .eq('email', cleanEmail)
        .eq('password', pass)
        .maybeSingle();

      if (error) {
        console.error("Login Supabase Error:", error);
        // If table doesn't exist, we notify the user
        if (error.code === '42P01') {
           setIsLoading(false);
           return { success: false, error: "Database-ka lama abuurin. Fadlan run-garee SQL Schema-ga." };
        }
        throw error;
      }

      if (!data) { 
        setIsLoading(false); 
        return { success: false, error: "Email-ka ama Password-ka waa khalad." }; 
      }

      setUser(data); 
      localStorage.setItem('user', JSON.stringify(data));
      setIsLoading(false);
      return { success: true };
    } catch (e: any) {
      console.error("Login Fatal Error:", e);
      setIsLoading(false);
      return { success: false, error: "Xiriirka database-ka waa go'an yahay ama Internet-ka." };
    }
  };

  const logout = () => { 
    setUser(null); 
    localStorage.removeItem('user'); 
    setActiveTab(Tab.DASHBOARD);
  };

  const updateCurrentUser = async (name: string, password?: string) => {
    if (!user) return { success: false };
    const updates: any = { name }; 
    if (password) updates.password = password;
    const { error } = await supabase.from('users').update(updates).eq('id', user.id);
    if (error) return { success: false, error: error.message };
    const updated = { ...user, ...updates }; 
    setUser(updated); 
    localStorage.setItem('user', JSON.stringify(updated));
    return { success: true };
  };

  // CRUD Helpers
  const addPatient = async (p: Patient) => {
    const { error } = await supabase.from('patients').insert([{ ...p, blood_type: p.bloodType, last_visit: p.lastVisit }]);
    if (!error) fetchData();
  };

  const processSale = async (items: any[], total: number, method: string, paid: number, patientId?: string, patientName?: string) => {
    const tx = {
      id: Date.now().toString(), date: new Date().toISOString(), total, paid_amount: paid, balance: total - paid,
      items: items.length, method, cashier_name: user?.name, user_id: user?.id,
      patient_id: patientId, patient_name: patientName, status: 'Completed', item_details: items
    };
    const { error } = await supabase.from('transactions').insert([tx]);
    if (!error) { fetchData(); return true; }
    return false;
  };

  const addProduct = async (p: Product) => { await supabase.from('products').insert([p]); fetchData(); };
  const updateProduct = async (p: Product) => { await supabase.from('products').update(p).eq('id', p.id); fetchData(); };
  const deleteProduct = async (id: string) => { await supabase.from('products').delete().eq('id', id); fetchData(); };
  const updatePatient = async (p: Patient) => { await supabase.from('patients').update(p).eq('id', p.id); fetchData(); };
  const deletePatient = async (id: string) => { await supabase.from('patients').delete().eq('id', id); fetchData(); };
  const addAppointment = async (a: Appointment) => { await supabase.from('appointments').insert([{ ...a, patient_name: a.patientName, doctor_name: a.doctorName }]); fetchData(); };
  const updateAppointment = async (a: Appointment) => { await supabase.from('appointments').update({ patient_name: a.patientName, doctor_name: a.doctorName, date: a.date, time: a.time, status: a.status, type: a.type }).eq('id', a.id); fetchData(); };
  const deleteAppointment = async (id: string) => { await supabase.from('appointments').delete().eq('id', id); fetchData(); };
  const updateAppointmentStatus = async (id: string, status: any) => { await supabase.from('appointments').update({ status }).eq('id', id); fetchData(); };
  const addExpense = async (e: Expense) => { await supabase.from('expenses').insert([e]); fetchData(); };
  const updateExpense = async (e: Expense) => { await supabase.from('expenses').update(e).eq('id', e.id); fetchData(); };
  const deleteExpense = async (id: string) => { await supabase.from('expenses').delete().eq('id', id); fetchData(); };
  const refundTransaction = async (id: string) => { await supabase.from('transactions').update({ status: 'Refunded' }).eq('id', id); fetchData(); };
  const addEmployee = async (e: Employee) => { await supabase.from('employees').insert([e]); fetchData(); };
  const deleteEmployee = async (id: string) => { await supabase.from('employees').delete().eq('id', id); fetchData(); };
  const addUser = async (u: User) => { 
    const { error } = await supabase.from('users').insert([u]); 
    if (!error) fetchData(); 
    return { success: !error, error: error?.message }; 
  };
  const deleteUser = async (id: string) => { await supabase.from('users').delete().eq('id', id); fetchData(); };
  const addPatientHistory = async (h: PatientHistory) => { await supabase.from('patient_history').insert([{ ...h, patient_id: h.patientId, doctor_name: h.doctorName }]); };
  const addPrescription = async (p: Prescription) => { await supabase.from('prescriptions').insert([{ ...p, patient_id: p.patientId, doctor_name: p.doctorName }]); };
  const settleBalance = async (patientId: string, patientName: string, amount: number, method: 'Cash' | 'EVC') => {
    await processSale([], amount, method, amount, patientId, patientName);
  };

  const t = (key: string) => (translations[language] as any)[key] || key;

  return (
    <AppContext.Provider value={{
      user, login, logout, updateCurrentUser, isLoading, language, setLanguage, activeTab, setActiveTab,
      products, addProduct, updateProduct, deleteProduct,
      patients, addPatient, updatePatient, deletePatient,
      appointments, addAppointment, updateAppointment, deleteAppointment, updateAppointmentStatus,
      transactions, salesReports, processSale, refundTransaction, settleBalance,
      employees, addEmployee, deleteEmployee,
      expenses, addExpense, updateExpense, deleteExpense,
      patientHistory, addPatientHistory,
      prescriptions, addPrescription,
      appUsers, addUser, deleteUser, t, activityLogs, logActivity
    }}>
      {children}
    </AppContext.Provider>
  );
};

