export const Reports: React.FC = () => {
  const { transactions, appUsers, salesReports, t, refundTransaction, logActivity } = useApp();
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedUserId, setSelectedUserId] = useState<string>('all');

  // Date Range Filtering
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>('');

  const formatDate = (dateStr: string) => {
    try {
      const date = new Date(dateStr);
      return isNaN(date.getTime()) ? dateStr : date.toLocaleString();
    } catch {
      return dateStr;
    }
  };

  const filteredTransactions = useMemo(() => {
    return transactions.filter(tx => {
      const txDateObj = new Date(tx.date);
      const txISODate = !isNaN(txDateObj.getTime()) ? txDateObj.toISOString().split('T')[0] : '';
      const txDateFull = formatDate(tx.date);

      const matchesSearch = tx.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            tx.method.toLowerCase().includes(searchTerm.toLowerCase()) ||
                            txDateFull.toLowerCase().includes(searchTerm.toLowerCase()) ||
                            (tx.cashierName && tx.cashierName.toLowerCase().includes(searchTerm.toLowerCase())) ||
                            (tx.patientName && tx.patientName.toLowerCase().includes(searchTerm.toLowerCase()));

      const matchesUser = selectedUserId === 'all' || tx.userId === selectedUserId;

      let matchesDate = true;
      if (startDate) matchesDate = matchesDate && txISODate >= startDate;
      if (endDate) matchesDate = matchesDate && txISODate <= endDate;

      return matchesSearch && matchesUser && matchesDate;
    });
  }, [transactions, searchTerm, selectedUserId, startDate, endDate]);

  const activeTransactions = filteredTransactions.filter(tx => tx.status !== 'Refunded');

  const totalRevenue = activeTransactions.reduce((acc, curr) => acc + (Number(curr.total) || 0), 0);
  const totalBalance = activeTransactions.reduce((acc, curr) => acc + (Number(curr.balance) || 0), 0);
  const averageTxValue = activeTransactions.length > 0 ? totalRevenue / activeTransactions.length : 0;

  const filteredSalesReports = useMemo(() => {
    return salesReports.filter(report => {
       let matches = true;
       if (startDate) matches = matches && report.date >= startDate;
       if (endDate) matches = matches && report.date <= endDate;
       return matches;
    }).sort((a, b) => a.date.localeCompare(b.date));
  }, [salesReports, startDate, endDate]);

  const handlePrint = () => {
    logActivity('Print Report', 'User printed the sales report');
    window.print();
  };

  const handleRefund = (id: string) => {
    if (window.confirm(t('refundConfirm'))) {
      refundTransaction(id);
    }
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-container');
    if (!element) return;
    logActivity('Download PDF', 'User downloaded sales report PDF');
    const opt = {
      margin: 0.2,
      filename: `Dhool_Report_${new Date().toISOString().split('T')[0]}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2 },
      jsPDF: { unit: 'in', format: 'a4', orientation: 'portrait' }
    };

    if (typeof html2pdf !== 'undefined') {
       html2pdf().set(opt).from(element).save();
    } else {
       alert("Loading PDF library... try again.");
    }
  };

  return (
    <div className="p-4 md:p-6 pb-24 md:pb-6 max-w-6xl mx-auto">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6 print:hidden">
        <h2 className="text-2xl font-bold text-gray-800">{t('reports')}</h2>

        <div className="flex gap-3 w-full md:w-auto">
          <button onClick={handleDownloadPDF} className="flex-1 md:flex-none px-4 py-2 bg-gray-100 text-gray-700 font-bold rounded-xl text-sm hover:bg-gray-200 transition-colors flex items-center justify-center gap-2">
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="3" x2="12" y2="15"/></svg>
            {t('downloadPdf')}
          </button>
          <button onClick={handlePrint} className="flex-1 md:flex-none px-4 py-2 bg-blue-600 text-white font-bold rounded-xl text-sm hover:bg-blue-700 transition-colors flex items-center justify-center gap-2 shadow-lg shadow-blue-100">
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="6 9 6 2 18 2 18 9"/><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><rect width="12" height="8" x="6" y="14"/></svg>
            {t('printReport')}
          </button>
        </div>
      </div>

      <div className="flex flex-col md:flex-row gap-4 mb-8 print:hidden items-end bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
        <div className="relative flex-1 w-full">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1">{t('searchPlaceholder')}</label>
          <div className="relative">
            <svg className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
            <input type="text" placeholder="Search ID, Method, Patient..." className="w-full pl-10 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:border-blue-500 shadow-sm" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
        </div>

        <div className="flex gap-2 w-full md:w-auto">
          <div className="flex-1"><label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1">Start Date</label><input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-2 text-sm focus:outline-none shadow-sm font-bold text-gray-700" /></div>
          <div className="flex-1"><label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1">End Date</label><input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-2 text-sm focus:outline-none shadow-sm font-bold text-gray-700" /></div>
        </div>

        <div className="w-full md:w-auto">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1">{t('cashier')}</label>
          <select value={selectedUserId} onChange={(e) => setSelectedUserId(e.target.value)} className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-2 text-sm focus:outline-none shadow-sm font-bold">
            <option value="all">{t('allUsers')}</option>
            {appUsers.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
          </select>
        </div>

        {(startDate || endDate) && <button onClick={() => { setStartDate(''); setEndDate(''); }} className="px-4 py-2 bg-gray-100 text-gray-500 rounded-xl hover:bg-gray-200 transition-colors text-xs font-bold">Clear Dates</button>}
      </div>

      <div id="report-container" className="space-y-8 bg-white print:p-8">
        <div className="hidden print:flex flex-col items-center mb-8 border-b-2 border-gray-100 pb-6"><Logo /><p className="text-sm text-gray-500 uppercase tracking-widest mt-4 font-bold">Sales & Revenue Report | {new Date().toLocaleDateString()}</p></div>

        <div className="mb-10">
          <div className="flex items-center gap-2 mb-4"><div className="w-1 h-6 bg-blue-600 rounded-full"></div><h3 className="text-lg font-bold text-gray-800">Sales Performance Overview</h3></div>

          <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
            <div className="bg-blue-600 rounded-2xl p-6 text-white shadow-xl shadow-blue-200"><p className="text-blue-200 font-medium text-xs uppercase mb-1">{t('totalRevenue')}</p><h3 className="text-3xl font-black">${totalRevenue.toFixed(2)}</h3><p className="text-[10px] opacity-70 mt-1">Based on filtered selection</p></div>
            <div className="bg-white rounded-2xl p-6 border border-gray-100 shadow-sm"><p className="text-gray-400 font-bold text-xs uppercase mb-1">Tx Count</p><h3 className="text-3xl font-black text-gray-800">{activeTransactions.length}</h3><p className="text-[10px] text-gray-400 mt-1">Total Transactions</p></div>
            <div className="bg-white rounded-2xl p-6 border border-gray-100 shadow-sm"><p className="text-gray-400 font-bold text-xs uppercase mb-1">Avg Value</p><h3 className="text-3xl font-black text-gray-800">${averageTxValue.toFixed(2)}</h3><p className="text-[10px] text-gray-400 mt-1">Per Transaction</p></div>
            <div className="bg-white rounded-2xl p-6 border border-gray-100 shadow-sm"><p className="text-red-500 font-bold text-xs uppercase mb-1">Outstanding</p><h3 className="text-3xl font-black text-red-600">${totalBalance.toFixed(2)}</h3><p className="text-[10px] text-gray-400 mt-1">Unpaid Dues</p></div>
          </div>

          {/* New Analytics Chart Section */}
          <div className="bg-white rounded-3xl p-6 border border-gray-100 shadow-sm mb-8 print:hidden">
            <div className="flex items-center justify-between mb-6">
               <h4 className="font-bold text-gray-800 text-sm uppercase tracking-wide">Sales Analytics (Daily)</h4>
               <div className="flex gap-4 text-[10px] font-bold">
                  <div className="flex items-center gap-1.5"><div className="w-2.5 h-2.5 bg-blue-600 rounded-sm"></div><span>Total Sales ($)</span></div>
                  <div className="flex items-center gap-1.5"><div className="w-2.5 h-2.5 bg-green-500 rounded-sm"></div><span>Tx Count</span></div>
               </div>
            </div>

            <div className="h-64 w-full">
              {filteredSalesReports.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={filteredSalesReports}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis 
                      dataKey="date" 
                      axisLine={false} 
                      tickLine={false} 
                      tick={{ fontSize: 10, fill: '#94a3b8' }} 
                      dy={10}
                    />
                    <YAxis 
                      yAxisId="left" 
                      orientation="left" 
                      stroke="#1155B3" 
                      axisLine={false} 
                      tickLine={false} 
                      tick={{ fontSize: 10, fill: '#1155B3' }} 
                    />
                    <YAxis 
                      yAxisId="right" 
                      orientation="right" 
                      stroke="#10b981" 
                      axisLine={false} 
                      tickLine={false} 
                      tick={{ fontSize: 10, fill: '#10b981' }} 
                    />
                    <Tooltip 
                      cursor={{ fill: '#f8fafc' }}
                      contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontSize: '12px' }}
                    />
                    <Bar yAxisId="left" dataKey="total_sales" fill="#1155B3" radius={[4, 4, 0, 0]} barSize={30} />
                    <Bar yAxisId="right" dataKey="transaction_count" fill="#10b981" radius={[4, 4, 0, 0]} barSize={15} />
                  </BarChart>
                </ResponsiveContainer>
              ) : (
                <div className="h-full flex items-center justify-center bg-gray-50 rounded-2xl border border-dashed border-gray-200">
                  <p className="text-gray-400 text-sm">No analytics data available for this range.</p>
                </div>
              )}
            </div>
          </div>

          {selectedUserId === 'all' && (
            <div className="bg-gray-50 rounded-3xl p-6 border border-gray-200 mb-8">
               <h4 className="font-bold text-gray-700 mb-4 text-sm uppercase tracking-wide">Historical Daily Aggregates</h4>
               <div className="overflow-x-auto">
                  <table className="w-full text-left text-sm">
                     <thead className="text-xs text-gray-400 uppercase font-black"><tr><th className="pb-3">Date</th><th className="pb-3 text-right">Total Sales</th><th className="pb-3 text-right">Transactions</th><th className="pb-3 text-right">Avg Value</th></tr></thead>
                     <tbody className="divide-y divide-gray-200">
                        {filteredSalesReports.length === 0 ? (
                           <tr><td colSpan={4} className="py-4 text-center text-gray-400">No historical reports found for this period.</td></tr>
                        ) : (
                           filteredSalesReports.map((report) => (
                              <tr key={report.date}><td className="py-2 font-bold text-gray-700">{report.date}</td><td className="py-2 text-right font-mono">${report.total_sales.toFixed(2)}</td><td className="py-2 text-right font-mono">{report.transaction_count}</td><td className="py-2 text-right font-mono text-gray-500">${report.average_value.toFixed(2)}</td></tr>
                           ))
                        )}
                     </tbody>
                  </table>
               </div>
            </div>
          )}
        </div>

        <div className="bg-white rounded-3xl p-6 shadow-sm border border-gray-100 overflow-hidden">
          <div className="flex items-center gap-2 mb-4"><div className="w-1 h-6 bg-gray-800 rounded-full"></div><h3 className="text-lg font-bold text-gray-800">{t('recentTransactions')}</h3></div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-gray-50 text-[10px] font-black text-gray-400 uppercase tracking-wider">
                 <tr><th className="p-3">ID</th><th className="p-3">{t('date')}</th><th className="p-3">Patient</th><th className="p-3">{t('cashier')}</th><th className="p-3">{t('method')}</th><th className="p-3 text-right">{t('total')}</th><th className="p-3 text-right">{t('amountPaid')}</th><th className="p-3 text-right">{t('status')}</th><th className="p-3 text-right print:hidden">{t('actions')}</th></tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {filteredTransactions.length === 0 ? <tr><td colSpan={9} className="p-8 text-center text-gray-400">No transactions found matching your filters.</td></tr> : filteredTransactions.map(tx => (
                    <tr key={tx.id} className={`hover:bg-gray-50 transition-colors ${tx.status === 'Refunded' ? 'opacity-50 grayscale bg-gray-50' : ''}`}>
                      <td className="p-3 text-[10px] font-mono text-gray-400">#{tx.id.slice(-6)}</td>
                      <td className="p-3 text-xs">{formatDate(tx.date)}</td>
                      <td className="p-3 text-xs font-bold text-gray-700">{tx.patientName || t('generalSale')}</td>
                      <td className="p-3 text-xs font-medium text-blue-600">{tx.cashierName || 'N/A'}</td>
                      <td className="p-3"><span className={`text-[10px] px-2 py-0.5 rounded-full font-black uppercase ${tx.method === 'EVC' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-700'}`}>{tx.method}</span></td>
                      <td className="p-3 text-right text-xs font-medium text-gray-500">${(Number(tx.total) || 0).toFixed(2)}</td>
                      <td className="p-3 text-right text-xs font-bold text-green-600">${(Number(tx.paidAmount) || 0).toFixed(2)}</td>
                      <td className="p-3 text-right"><span className={`text-[9px] px-2 py-0.5 rounded uppercase font-black ${tx.status === 'Refunded' ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'}`}>{tx.status || 'Completed'}</span></td>
                      <td className="p-3 text-right print:hidden">
                        {tx.status !== 'Refunded' && <button onClick={() => handleRefund(tx.id)} className="p-1.5 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all" title={t('refund')}><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/></svg></button>}
                      </td>
                    </tr>
                  ))
                }
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};
